class BankAccount:
    def __init__(self, account_id: str, owner: str):
        self.account_id = account_id
        self.owner = owner
        self._balance = 0.0          # O(1) attribute access
        self._transactions = []      # O(1) append

    def deposit(self, amount: float) -> float:
        if amount <= 0:
            raise ValueError("Amount must be positive")
        self._balance += amount
        self._transactions.append(("deposit", amount))
        return self._balance

    def get_balance(self) -> float:
        return self._balance

    def __repr__(self) -> str:
        return f"BankAccount({self.account_id!r}, balance={self._balance})"

acc = BankAccount("ACC001", "Alice")
print(acc.deposit(500))   # 500.0
print(acc)                # BankAccount('ACC001', balance=500.0)

class Account:
    def __init__(self, account_id: str):
        self.account_id = account_id
        self._balance = 0.0

    def deposit(self, amount: float) -> None:
        self._balance += amount

    def get_balance(self) -> float:
        return self._balance


class SavingsAccount(Account):
    def __init__(self, account_id: str, interest_rate: float):
        super().__init__(account_id)
        self.interest_rate = interest_rate

    def apply_interest(self) -> float:
        interest = self._balance * self.interest_rate
        self._balance += interest
        return self._balance


acc = SavingsAccount("SAV001", 0.05)
acc.deposit(1000)
print(acc.apply_interest())   # 1050.0

class Bank:
    def __init__(self):
        self._accounts: dict[str, BankAccount] = {}

    def create_account(self, account_id: str, owner: str) -> str:
        if account_id in self._accounts:
            return "ERROR: Account exists"
        self._accounts[account_id] = BankAccount(account_id, owner)
        return "OK"

    def deposit(self, account_id: str, amount: float) -> str:
        if account_id not in self._accounts:
            return "ERROR: Account not found"
        balance = self._accounts[account_id].deposit(amount)
        return str(balance)

    def get_balance(self, account_id: str) -> str:
        if account_id not in self._accounts:
            return "ERROR: Account not found"
        return str(self._accounts[account_id].get_balance())

