class Book:
    def __init__(self, title: str, author: str):
        self.title = title
        self.author = author
        self.available = True

class Library:
    def __init__(self):
        self._books: dict[str, Book] = {}

    def add_book(self, title: str, author: str) -> None:
        self._books[title] = Book(title, author)

    def checkout(self, title: str) -> str:
        book = self._books.get(title)
        if book is None or not book.available:
            return 'NOT_AVAILABLE'
        book.available = False
        return 'OK'

    def return_book(self, title: str) -> str:
        book = self._books.get(title)
        if book:
            book.available = True
        return 'OK'

lib = Library()
lib.add_book("Python Cookbook", "David Beazley")
print(lib.checkout("Python Cookbook"))   # OK
print(lib.checkout("Python Cookbook"))  # NOT_AVAILABLE
print(lib.return_book("Python Cookbook"))  # OK

