from typing import Optional, Union
from dataclasses import dataclass, field

@dataclass
class Record:
    key: str
    value: Union[str, int, float]
    ttl: Optional[float] = None    # None means no expiry

    def is_expired(self, current_time: float) -> bool:
        if self.ttl is None:
            return False
        return current_time > self.ttl

def get_record(
    store: dict[str, Record],
    key: str,
    current_time: float
) -> Optional[str]:
    if key not in store:
        return None
    record = store[key]
    if record.is_expired(current_time):
        del store[key]
        return None
    return str(record.value)

