import heapq
from dataclasses import dataclass, field

@dataclass
class TaskScheduler:
    _heap: list = field(default_factory=list)
    _cancelled: set = field(default_factory=set)
    _tasks: dict = field(default_factory=dict)  # task_id -> name

    def add_task(self, task_id: str, name: str,
                 priority: int) -> bool:
        if task_id in self._tasks:
            return False                         # duplicate
        self._tasks[task_id] = name
        heapq.heappush(self._heap, (priority, task_id, name))
        return True

    def run_next(self) -> str | None:
        while self._heap:
            priority, task_id, name = heapq.heappop(self._heap)
            if task_id not in self._cancelled:
                del self._tasks[task_id]
                return name                      # executed
        return None

    def cancel_task(self, task_id: str) -> bool:
        if task_id not in self._tasks:
            return False
        self._cancelled.add(task_id)
        del self._tasks[task_id]
        return True

import heapq
from dataclasses import dataclass, field

@dataclass
class TimedScheduler:
    _heap: list = field(default_factory=list)
    _cancelled: set = field(default_factory=set)
    _tasks: dict = field(default_factory=dict)

    def add_task(self, task_id: str, name: str,
                 priority: int, run_at: int = 0) -> bool:
        if task_id in self._tasks:
            return False
        self._tasks[task_id] = (name, priority, run_at)
        # Sort by (run_at, priority) — earlier time and lower number = first
        heapq.heappush(self._heap, (run_at, priority, task_id, name))
        return True

    def run_next(self, current_time: int) -> str | None:
        while self._heap:
            run_at, priority, task_id, name = self._heap[0]
            if run_at > current_time:
                break                            # not due yet
            heapq.heappop(self._heap)
            if task_id not in self._cancelled:
                del self._tasks[task_id]
                return name
        return None

    def run_all(self, current_time: int) -> list[str]:
        results = []
        while (name := self.run_next(current_time)) is not None:
            results.append(name)
        return results

# Extended add_task to accept interval
def add_task(self, task_id: str, name: str, priority: int,
             run_at: int = 0, interval: int | None = None) -> bool:
    if task_id in self._tasks:
        return False
    self._tasks[task_id] = {
        "name": name, "priority": priority,
        "run_at": run_at, "interval": interval
    }
    heapq.heappush(self._heap, (run_at, priority, task_id, name))
    return True

def run_next(self, current_time: int) -> str | None:
    while self._heap:
        run_at, priority, task_id, name = self._heap[0]
        if run_at > current_time:
            break
        heapq.heappop(self._heap)
        if task_id in self._cancelled:
            continue
        info = self._tasks[task_id]
        if info["interval"] is not None:
            # Re-schedule recurring task
            next_run = run_at + info["interval"]
            info["run_at"] = next_run
            heapq.heappush(
                self._heap, (next_run, priority, task_id, name)
            )
        else:
            del self._tasks[task_id]         # one-shot: remove
        return name
    return None

def get_schedule(self) -> list[tuple]:
    return sorted(
        [(tid, info["run_at"]) for tid, info in self._tasks.items()
         if tid not in self._cancelled],
        key=lambda x: x[1]
    )

