from dataclasses import dataclass, field
@dataclass
class CacheEntry:
    value: str
    size: int          # pre-computed len(value)
@dataclass
class SizedLRUCache:
    max_bytes: int
    _cache: OrderedDict = field(default_factory=OrderedDict)  # key → CacheEntry
    _total_size: int = 0
    def put(self, key: str, value: str) -> bool:
        new_size = len(value)
        if new_size > self.max_bytes:
            return False             # single item too large
        # Remove existing entry first (size accounting)
        if key in self._cache:
            self._total_size -= self._cache[key].size
            del self._cache[key]
        # Evict LRU items until there is room
        while self._total_size + new_size > self.max_bytes and self._cache:
            _, evicted = self._cache.popitem(last=False)
            self._total_size -= evicted.size
        self._cache[key] = CacheEntry(value=value, size=new_size)
        self._total_size += new_size
        return True

