import threading

class BankAccount:
    def __init__(self, account_id: str, balance: float):
        self.id = account_id
        self.balance = balance
        self._lock = threading.RLock()

class Bank:
    def __init__(self):
        self._accounts: dict[str, BankAccount] = {}

    def create_account(self, account_id: str, initial: float) -> None:
        self._accounts[account_id] = BankAccount(account_id, initial)

    def transfer(self, from_id: str, to_id: str, amount: float) -> bool:
        src = self._accounts.get(from_id)
        dst = self._accounts.get(to_id)
        if not src or not dst:
            return False

        first, second = (src, dst) if src.id < dst.id else (dst, src)
        with first._lock:
            with second._lock:
                if src.balance < amount:
                    return False
                src.balance -= amount
                dst.balance += amount
                return True

