    def __init__(self):
        self._store: dict[str, Record] = {}

    def set(self, key: str, value: str) -> None:
        self._store[key] = Record(value=value)

    def set_with_ttl(self, key: str, value: str, ttl: float) -> None:
        self._store[key] = Record(value=value, expires_at=time.time() + ttl)

    def get(self, key: str) -> str:
        record = self._store.get(key)
        if record is None:
            return ""
        if not record.is_valid():
            del self._store[key]
            return ""
        return record.value

    def delete(self, key: str) -> str:
        if key in self._store:
            del self._store[key]
            return "1"
        return "0"

    def scan(self, prefix: str) -> list:
        return [
            (k, r.value)
            for k, r in sorted(self._store.items())
            if k.startswith(prefix) and r.is_valid()
        ]


