import threading
import time

class Database:
    def __init__(self):
        self._store: dict[str, str] = {}
        self._expiry: dict[str, float] = {}
        self._lock = threading.RLock()

    def _is_expired(self, key: str) -> bool:
        return key in self._expiry and time.time() > self._expiry[key]

    def set(self, key: str, value: str, ttl: float | None = None) -> None:
        with self._lock:
            self._store[key] = value
            if ttl is not None:
                self._expiry[key] = time.time() + ttl
            elif key in self._expiry:
                del self._expiry[key]

    def get(self, key: str) -> str:
        with self._lock:
            if self._is_expired(key):
                del self._store[key]; del self._expiry[key]
                return ""
            return self._store.get(key, "")

    def delete(self, key: str) -> str:
        with self._lock:
            if key not in self._store or self._is_expired(key):
                return "0"
            del self._store[key]
            self._expiry.pop(key, None)
            return "1"

    def set_many(self, pairs: list[tuple[str, str]]) -> None:
        with self._lock:
            for key, value in pairs:
                self._store[key] = value
                self._expiry.pop(key, None)

    def get_many(self, keys: list[str]) -> dict[str, str]:
        with self._lock:
            result = {}
            for key in keys:
                if key in self._store and not self._is_expired(key):
                    result[key] = self._store[key]
            return result

db = Database()

