import copy
import threading

class Database:
    def __init__(self):
        self._store: dict[str, str] = {}
        self._expiry: dict[str, float] = {}
        self._lock = threading.RLock()
        self._snapshots: dict[int, dict] = {}
        self._next_snapshot_id = 1

    def set(self, key: str, value: str) -> None:
        with self._lock:
            self._store[key] = value

    def get(self, key: str) -> str:
        with self._lock:
            return self._store.get(key, "")

    def snapshot(self) -> int:
        with self._lock:
            sid = self._next_snapshot_id
            self._snapshots[sid] = copy.deepcopy({'store': self._store, 'expiry': self._expiry})
            self._next_snapshot_id += 1
            return sid

    def restore(self, snapshot_id: int) -> bool:
        with self._lock:
            if snapshot_id not in self._snapshots:
                return False
            saved = copy.deepcopy(self._snapshots[snapshot_id])
            self._store = saved['store']
            self._expiry = saved['expiry']
            return True

    def list_snapshots(self) -> list[int]:
        with self._lock:
            return sorted(self._snapshots.keys())

    def delete_snapshot(self, snapshot_id: int) -> bool:
        with self._lock:
            if snapshot_id not in self._snapshots:
                return False
            del self._snapshots[snapshot_id]
            return True

db = Database()

