        if account_id not in self._accounts:
            return "ERROR: not found"
        self._accounts[account_id].balance += amount
        if self._cashback_rate > 0:
            cashback_amount = amount * self._cashback_rate
            heapq.heappush(
                self._pending_cashback,
                PendingCashback(current_time + 86400, account_id, cashback_amount)
            )
        return str(self._accounts[account_id].balance)

    def process_cashback(self, current_time: float) -> int:
