import threading
from collections import defaultdict

class Bank:
    def __init__(self):
        self._balances: dict[str, float] = {}
        self._locks: dict[str, threading.Lock] = defaultdict(threading.Lock)

    def create_account(self, account_id: str, initial_balance: float = 0) -> bool:
        if account_id in self._balances:
            return False
        self._balances[account_id] = initial_balance
        return True

    def deposit(self, account_id: str, amount: float) -> float | None:
        if account_id not in self._balances: return None
        with self._locks[account_id]:
            self._balances[account_id] += amount
            return self._balances[account_id]

    def transfer(self, from_id: str, to_id: str, amount: float) -> bool:
        if from_id not in self._balances or to_id not in self._balances:
            return False
        first, second = sorted([from_id, to_id])
        with self._locks[first]:
            with self._locks[second]:
                if self._balances[from_id] < amount:
                    return False
                self._balances[from_id] -= amount
                self._balances[to_id] += amount
                return True

    def concurrent_transfer_batch(self, transfers: list[tuple]) -> int:
        results = []
        result_lock = threading.Lock()
        def do_transfer(from_id, to_id, amount):
            ok = self.transfer(from_id, to_id, amount)
            with result_lock:
                results.append(ok)
        threads = [threading.Thread(target=do_transfer, args=t) for t in transfers]
        for t in threads: t.start()
        for t in threads: t.join()
        return sum(results)

