class FileCache:
    def __init__(self, max_bytes: int = 1000):
        self.max_bytes = max_bytes
        self._cache: OrderedDict[str, CacheEntry] = OrderedDict()
        self._total_size: int = 0
    def put(self, filename: str, content: str) -> str:
        new_size = len(content)
        if new_size > self.max_bytes:
            return "ERROR: too large"
        if filename in self._cache:
            self._total_size -= self._cache[filename].size
            del self._cache[filename]
        while self._total_size + new_size > self.max_bytes and self._cache:
            _, evicted = self._cache.popitem(last=False)
            self._total_size -= evicted.size
        self._cache[filename] = CacheEntry(value=content, size=new_size)
        self._total_size += new_size
        return "OK"
    def get(self, filename: str) -> str:
        if filename not in self._cache:
            return ""
        entry = self._cache[filename]
        entry.access_count += 1
        entry.last_accessed = time.time()
        self._cache.move_to_end(filename)
        return entry.value
    def top_accessed(self, n: int) -> list:
        ranked = sorted(self._cache.items(), key=lambda x: -x[1].access_count)
        return [(name, entry.access_count) for name, entry in ranked[:n]]
    def stats(self, filename: str) -> Optional[dict]:
        if filename not in self._cache:
            return None
        entry = self._cache[filename]
        return {
            "size": entry.size,
            "access_count": entry.access_count,
            "last_accessed": entry.last_accessed,
        }
    def report(self) -> dict:
        if not self._cache:
            return {"total_files": 0, "total_bytes": 0, "most_accessed": None}
        most_accessed = max(self._cache.items(), key=lambda x: x[1].access_count)
        return {
            "total_files": len(self._cache),
            "total_bytes": self._total_size,
            "most_accessed": most_accessed[0],
        }
