import threading
from collections import OrderedDict
from dataclasses import dataclass

@dataclass
class CacheEntry:
    content: str
    size: int

class FileCache:
    def __init__(self, max_bytes: int):
        self._max_bytes = max_bytes
        self._cache: OrderedDict[str, CacheEntry] = OrderedDict()
        self._used_bytes = 0
        self._hits = 0
        self._misses = 0
        self._lock = threading.RLock()

    def _evict_unlocked(self):
        while self._used_bytes > self._max_bytes and self._cache:
            _, evicted = self._cache.popitem(last=False)
            self._used_bytes -= evicted.size

    def _put_unlocked(self, key: str, content: str, size: int) -> bool:
        if size > self._max_bytes: return False
        if key in self._cache:
            self._used_bytes -= self._cache[key].size
            del self._cache[key]
        self._cache[key] = CacheEntry(content=content, size=size)
        self._used_bytes += size
        self._evict_unlocked()
        return True

    def _get_unlocked(self, key: str) -> str | None:
        if key not in self._cache:
            self._misses += 1
            return None
        self._cache.move_to_end(key)
        self._hits += 1
        return self._cache[key].content

    def get(self, key: str) -> str | None:
        with self._lock:
            return self._get_unlocked(key)

    def put(self, key: str, content: str, size: int) -> bool:
        with self._lock:
            return self._put_unlocked(key, content, size)

    def bulk_put(self, files: list[tuple[str, str, int]]) -> int:
        with self._lock:
            count = 0
            for key, content, size in files:
                if self._put_unlocked(key, content, size):
                    count += 1
            return count

    def bulk_get(self, keys: list[str]) -> dict[str, str]:
        with self._lock:
            result = {}
            for key in keys:
                val = self._get_unlocked(key)
                if val is not None:
                    result[key] = val
            return result

cache = FileCache(max_bytes=1000)

