    def __init__(self):
        self._meta: dict[tuple, FileMeta] = {}
        self._content: dict[tuple, str] = {}
        self._symlinks: dict[tuple, str] = {}
        self._mounts: dict[tuple, str] = {}

    def create_symlink(self, src_dir: str, src_name: str, target_path: str) -> bool:
        key = (src_dir, src_name)
        if key in self._meta or key in self._symlinks:
            return False
        self._symlinks[key] = target_path
        return True

    def resolve_path(self, dir_name: str, file_name: str) -> tuple[str, str] | None:
        visited = set()
        for _ in range(10):
            key = (dir_name, file_name)
            if key in visited:
                return None
            visited.add(key)
            if key not in self._symlinks:
                return (dir_name, file_name)
            parts = self._symlinks[key].strip('/').split('/')
            if len(parts) < 2:
                return None
            dir_name, file_name = parts[-2], parts[-1]
        return None

    def _resolve_mount(self, dir_name: str, file_name: str) -> tuple[str, str]:
        key = (dir_name, file_name)
        if key in self._mounts:
            return (self._mounts[key], file_name)
        return (dir_name, file_name)

    def read_file(self, dir_name: str, file_name: str) -> str | None:
        resolved = self.resolve_path(dir_name, file_name)
        if resolved is None:
            return None
        d, n = self._resolve_mount(*resolved)
        return self._content.get((d, n))

    def write_file(self, dir_name: str, file_name: str, content: str) -> bool:
        resolved = self.resolve_path(dir_name, file_name)
        if resolved is None:
            return False
        d, n = self._resolve_mount(*resolved)
        self._content[(d, n)] = content
        self._meta[(d, n)] = FileMeta(name=n, is_dir=False, size=len(content))
        return True

    def mount(self, mount_dir: str, mount_name: str, source_dir: str) -> bool:
        self._mounts[(mount_dir, mount_name)] = source_dir
        return True

    def unmount(self, mount_dir: str, mount_name: str) -> bool:
        key = (mount_dir, mount_name)
        if key not in self._mounts:
            return False
        del self._mounts[key]
        return True

fs = FileSystem()

