from dataclasses import dataclass

@dataclass
class FileMeta:
    name: str
    is_dir: bool
    size: int = 0
    owner: str = "root"
    mode: int = 0o644

class FileSystem:
    def __init__(self):
        self._meta: dict[tuple, FileMeta] = {}
        self._content: dict[tuple, str] = {}
        self._quotas: dict[str, int] = {}
        self._audit_log: list[dict] = []
        self._clock = 0

    def _tick(self) -> int:
        self._clock += 1
        return self._clock

    def set_quota(self, owner: str, max_bytes: int) -> None:
        self._quotas[owner] = max_bytes

    def get_usage(self, owner: str) -> dict:
        used = sum(m.size for m in self._meta.values() if m.owner == owner)
        quota = self._quotas.get(owner, -1)
        return {'used': used, 'quota': quota, 'remaining': quota - used if quota >= 0 else -1}

    def write_file(self, dir_name: str, file_name: str, content: str,
                   owner: str = "root") -> bool:
        key = (dir_name, file_name)
        new_size = len(content)
        old_size = self._meta[key].size if key in self._meta else 0
        if owner in self._quotas:
            current = sum(m.size for m in self._meta.values() if m.owner == owner)
            if current - old_size + new_size > self._quotas[owner]:
                return False
        self._content[key] = content
        self._meta[key] = FileMeta(name=file_name, is_dir=False, size=new_size, owner=owner)
        self._audit_log.append({'time': self._tick(), 'op': 'write', 'owner': owner, 'path': f'{dir_name}/{file_name}'})
        return True

    def delete_file(self, dir_name: str, file_name: str) -> bool:
        key = (dir_name, file_name)
        if key not in self._meta:
            return False
        owner = self._meta[key].owner
        del self._meta[key]
        self._content.pop(key, None)
        self._audit_log.append({'time': self._tick(), 'op': 'delete', 'owner': owner, 'path': f'{dir_name}/{file_name}'})
        return True

    def get_audit_log(self, owner: str | None = None) -> list[dict]:
        if owner is None:
            return list(self._audit_log)
        return [e for e in self._audit_log if e['owner'] == owner]

fs = FileSystem()

