class RateLimiter(RateLimiterBase):
    def __init__(self, max_requests: int, window_ms: int):
        self._max_requests = max_requests
        self._window_ms = window_ms
        # user_id -> (window_key, count)
        self._state: dict[str, tuple[int, int]] = {}
    def allow_request(self, user_id: str, timestamp: int) -> bool:
        current_window = timestamp // self._window_ms
        stored_window, count = self._state.get(user_id, (-1, 0))
        if stored_window != current_window:
            count = 0
        if count >= self._max_requests:
            return False
        self._state[user_id] = (current_window, count + 1)
        return True
