from collections import deque

class RateLimiter:
    def __init__(self, limit: int, window_seconds: int):
        self._default_limit = limit
        self._window = window_seconds
        self._logs: dict[str, deque] = {}
        self._custom_limits: dict[str, int] = {}
        self._burst = 0
        self._penalty = 0
        self._cooldowns: dict[str, int] = {}

    def set_user_limit(self, user_id: str, limit: int) -> None:
        self._custom_limits[user_id] = limit

    def set_burst(self, burst: int, penalty_seconds: int) -> None:
        self._burst = burst
        self._penalty = penalty_seconds

    def _get_limit(self, user_id: str) -> int:
        return self._custom_limits.get(user_id, self._default_limit)

    def allow_request(self, user_id: str, timestamp: int) -> bool:
        if timestamp < self._cooldowns.get(user_id, 0):
            return False
        if user_id not in self._logs:
            self._logs[user_id] = deque()
        dq = self._logs[user_id]
        cutoff = timestamp - self._window
        while dq and dq[0] <= cutoff:
            dq.popleft()
        limit = self._get_limit(user_id)
        count = len(dq)
        if count >= limit + self._burst:
            return False
        if count >= limit:
            self._cooldowns[user_id] = timestamp + self._penalty
        dq.append(timestamp)
        return True


