class RateLimiter:
    def __init__(self, max_tokens: float, refill_rate: float):
        self._max_tokens = max_tokens
        self._refill_rate = refill_rate
        self._tokens: dict[str, float] = {}
        self._last_refill: dict[str, float] = {}

    def _get_current_tokens(self, user_id: str, current_time: float) -> float:
        last = self._last_refill.get(user_id, current_time)
        elapsed = max(0, current_time - last)
        current = self._tokens.get(user_id, self._max_tokens)
        return min(self._max_tokens, current + elapsed * self._refill_rate)

    def allow_request(self, user_id: str, current_time: float, cost: float = 1) -> bool:
        tokens = self._get_current_tokens(user_id, current_time)
        self._last_refill[user_id] = current_time
        if tokens < cost:
            self._tokens[user_id] = tokens
            return False
        self._tokens[user_id] = tokens - cost
        return True

    def get_tokens(self, user_id: str, current_time: float) -> float:
        return self._get_current_tokens(user_id, current_time)

    def export_state(self) -> dict:
        return dict(self._tokens)

    def sync_state(self, other_state: dict) -> None:
        for user_id, other_tokens in other_state.items():
            self_tokens = self._tokens.get(user_id, self._max_tokens)
            self._tokens[user_id] = min(self_tokens, other_tokens)

