        self._last_refill: dict[str, float] = {}
        self._outcomes: dict[str, deque] = {}

    def _get_rate(self, user_id: str) -> float:
        return self._effective_rate.get(user_id, self._base_rate)

    def allow_request(self, user_id: str, current_time: float, cost: float = 1) -> bool:
        last = self._last_refill.get(user_id, current_time)
        elapsed = max(0, current_time - last)
        current = self._tokens.get(user_id, self._max_tokens)
        tokens = min(self._max_tokens, current + elapsed * self._get_rate(user_id))
        self._last_refill[user_id] = current_time
        if tokens < cost:
            self._tokens[user_id] = tokens
            return False
        self._tokens[user_id] = tokens - cost
        return True

    def record_outcome(self, user_id: str, current_time: float, success: bool) -> None:
        if user_id not in self._outcomes:
            self._outcomes[user_id] = deque()
        self._outcomes[user_id].append((current_time, success))

    def get_error_rate(self, user_id: str, window_seconds: int, current_time: float) -> float:
        if user_id not in self._outcomes:
            return 0.0
        cutoff = current_time - window_seconds
        recent = [(t, s) for t, s in self._outcomes[user_id] if t >= cutoff]
        if not recent:
            return 0.0
        return sum(1 for _, s in recent if not s) / len(recent)

    def adapt_limit(self, user_id: str, current_time: float) -> float:
        error_rate = self.get_error_rate(user_id, 60, current_time)
        current_rate = self._get_rate(user_id)
        if error_rate > 0.5:
            new_rate = max(0.1, current_rate / 2)
        elif error_rate < 0.1:
            new_rate = self._base_rate
        else:
            new_rate = current_rate
        self._effective_rate[user_id] = new_rate
        return new_rate

    def reset_adaptation(self, user_id: str) -> None:
        self._effective_rate.pop(user_id, None)
        self._outcomes.pop(user_id, None)

