import heapq

class TaskScheduler:
    def __init__(self):
        self._heap: list = []
        self._task_ids: set = set()
        self._cancelled: set = set()
        self._done: set = set()
        self._deps: dict[str, set] = {}
        self._names: dict[str, str] = {}

    def _has_cycle(self, new_id: str, deps: list[str]) -> bool:
        graph: dict[str, set] = {tid: set() for tid in self._task_ids}
        graph[new_id] = set()
        for tid, dep_set in self._deps.items():
            for d in dep_set:
                if d not in graph: graph[d] = set()
                graph[d].add(tid)
        for d in deps:
            if d not in graph: graph[d] = set()
            graph[d].add(new_id)
        visited = set()
        stack = list(graph.get(new_id, set()))
        while stack:
            node = stack.pop()
            if node == new_id: return True
            if node in visited: continue
            visited.add(node)
            stack.extend(graph.get(node, set()))
        return False

    def add_task(self, task_id: str, name: str, priority: int,
                 run_at: int = 0, deps: list[str] = []) -> bool:
        if task_id in self._task_ids: return False
        if self._has_cycle(task_id, deps): return False
        self._task_ids.add(task_id)
        self._deps[task_id] = set(deps)
        self._names[task_id] = name
        heapq.heappush(self._heap, (run_at, priority, task_id, name))
        return True

    def mark_done(self, task_id: str) -> None:
        self._done.add(task_id)

    def run_next(self, current_time: int) -> str | None:
        deferred = []
        result = None
        while self._heap:
            run_at, priority, task_id, name = heapq.heappop(self._heap)
            if run_at > current_time:
                heapq.heappush(self._heap, (run_at, priority, task_id, name))
                break
            if task_id in self._cancelled: continue
            if not self._deps.get(task_id, set()).issubset(self._done):
                deferred.append((run_at, priority, task_id, name))
                continue
            result = name
            break
        for item in deferred:
            heapq.heappush(self._heap, item)
        return result

    def get_ready(self, current_time: int) -> list[str]:
        ready = []
        for run_at, priority, task_id, name in self._heap:
            if run_at > current_time: continue
            if task_id in self._cancelled: continue
            if self._deps.get(task_id, set()).issubset(self._done):
                ready.append((priority, run_at, task_id))
        return [tid for _, _, tid in sorted(ready)]

sched = TaskScheduler()

