import heapq

class TaskScheduler:
    def __init__(self):
        self._heap: list = []
        self._task_ids: set = set()
        self._cancelled: set = set()
        self._done: set = set()
        self._deps: dict[str, set] = {}
        self._names: dict[str, str] = {}
        self._workers: dict[str, dict] = {}
        self._assigned: dict[str, str] = {}

    def add_task(self, task_id: str, name: str, priority: int,
                 run_at: int = 0, deps: list[str] = []) -> bool:
        if task_id in self._task_ids: return False
        self._task_ids.add(task_id)
        self._deps[task_id] = set(deps)
        self._names[task_id] = name
        heapq.heappush(self._heap, (run_at, priority, task_id, name))
        return True

    def add_worker(self, worker_id: str) -> bool:
        if worker_id in self._workers: return False
        self._workers[worker_id] = {'assigned': 0, 'completed': 0, 'failed': 0, 'current_task': None}
        return True

    def assign_next(self, worker_id: str, current_time: int) -> str | None:
        if worker_id not in self._workers: return None
        if self._workers[worker_id]['current_task'] is not None: return None
        remaining = []
        result = None
        while self._heap:
            run_at, priority, task_id, name = heapq.heappop(self._heap)
            if (run_at <= current_time
                    and task_id not in self._cancelled
                    and task_id not in self._assigned
                    and self._deps.get(task_id, set()).issubset(self._done)
                    and result is None):
                self._assigned[task_id] = worker_id
                self._workers[worker_id]['assigned'] += 1
                self._workers[worker_id]['current_task'] = task_id
                result = name
            else:
                remaining.append((run_at, priority, task_id, name))
        for item in remaining:
            heapq.heappush(self._heap, item)
        return result

    def complete_task(self, worker_id: str, task_id: str, success: bool) -> bool:
        if worker_id not in self._workers: return False
        if self._assigned.get(task_id) != worker_id: return False
        del self._assigned[task_id]
        self._workers[worker_id]['current_task'] = None
        if success:
            self._done.add(task_id)
            self._workers[worker_id]['completed'] += 1
        else:
            self._workers[worker_id]['failed'] += 1
        return True

    def get_worker_stats(self) -> dict[str, dict]:
        return {wid: {k: v for k, v in s.items() if k != 'current_task'}
                for wid, s in self._workers.items()}

    def get_pending_count(self, current_time: int) -> int:
        return sum(
            1 for run_at, _, task_id, _ in self._heap
            if run_at <= current_time
            and task_id not in self._cancelled
            and task_id not in self._assigned
            and self._deps.get(task_id, set()).issubset(self._done)
        )

sched = TaskScheduler()

